  var mExp = textoBruto.match(/Expediente:\s*([^\n\r]+)/i);
  var mSexo = textoBruto.match(/Sexo:\s*([^\n\r]+)/i);
  var mEdad = textoBruto.match(/Edad:\s*([^\n\r]+)/i);
