    var prefs = {
      showBhExtendedLine: !!o.showBhExtendedLine,
      hideGasoAdvInterp: !!o.hideGasoAdvInterp,
      quickLabOutput: !!o.quickLabOutput
    };
    if (isAbgAnalysisHidden()) prefs.hideGasoAdvInterp = true;
