    medication: p.medication || "",
    route: p.route || "",
    doseValue: p.doseValue != null ? p.doseValue : "",
    doseUnit: p.doseUnit || "",
    dilution: p.dilution || "",
    frequency: p.frequency || "",
    infusionRateMlHr: p.infusionRateMlHr != null ? p.infusionRateMlHr : null,
    comments: p.comments || "",
