    /\bc\s*\/\s*\d+\s*h(?:oras?)?(?:\s*\([^)]*\))?/i,
    /\bcada\s+\d+\s*h(?:oras?)?/i,
    /\bq\s*\d+\s*h\b/i,
    /\d+\s*h\s+c\/\d+\s*h/i,
    /dosis\s+[úu]nica\s+diaria/i,
    /c\/12\s*h/i,
    /c\/8\s*h/i,
    /c\/6\s*h/i,
    /c\/24\s*h/i,
    /c\/4\s*[–-]\s*6\s*h/i
