function pathologyBranchLabelFor(branchId) {
  var hit = MANEJO_PATHOLOGY_BRANCHES.find(function(b) {
    return b.id === branchId;
  });
  return hit ? hit.label : branchId;
}
function findPathologyById(id) {
  if (!id) return null;
  return MANEJO_PATHOLOGIES.find(function(p) {
    return p.id === id;
  }) || null;
}
function pathologyMatchesSearch(entry2, q) {
  if (!q) return true;
  var needle = q.toLowerCase();
  var hay = entry2.title + " " + entry2.summary + " " + (entry2.definition || "") + " " + (entry2.tags || []).join(" ") + " " + pathologyBranchLabelFor(entry2.branch);
  return hay.toLowerCase().indexOf(needle) >= 0;
}
function getRelatedPathologies(pathologyId, all) {
  var entry2 = findPathologyById(pathologyId);
  if (!entry2 || !entry2.relatedPathologyIds) return [];
  return (all || MANEJO_PATHOLOGIES).filter(function(p) {
    return entry2.relatedPathologyIds.indexOf(p.id) >= 0;
  });
}
function pathologyStepCount(entry2) {
  var n = 0;
  (entry2.sections || []).forEach(function(sec) {
    (sec.items || []).forEach(function(item) {
      if (item.type === "protocol" || item.type === "text" || item.type === "recommendation") {
        n++;
      }
    });
  });
  return n;
}

